    updateCurrentPage();

    const checkScrollable = () => {
        if (document.body.scrollHeight <= window.innerHeight) {

            if (hasMore) {
                loadNextPage();
            } else if (hasPrevious) {
                loadPreviousPage();
            }
        }
    };


    checkScrollable();
}



