<script>
function jiazai(that){
	url = that.value;
	arr=document.querySelectorAll(".yearbuttons button");
	for(i=0;i<arr.length;i++){
		arr[i].className="year";
	}
	that.className ="year active";
	fetch(url).then(function(response) {
    return response.json();
  }).then(function(myJson) {
    list =myJson.data.videos;
    html="";
   for(i in list){
     	$=list[i];
	html+="<button value=\"http:"+$.pageUrl+"\" onclick=\"change(this)\">"+String($.subTitle).replace(/\s.*/,'')+"</button>"
	}
	document.querySelector(".buttons").innerHTML=html;
	});
}
function changejie(that){
	arr=document.querySelectorAll(".jiexi button");
	for(i=0;i<arr.length;i++){
		arr[i].className="";
	}
	arr1=document.querySelectorAll(".buttons button");
	for(i=0;i<arr1.length;i++){
		arr1[i].className="";
	}
	that.className="jiexiactive";
}
function change(that){
	arr=document.querySelectorAll(".buttons button");
	for(i=0;i<arr.length;i++){
		arr[i].className="";
	}
	id=document.getElementById("iframe");
	class1=document.querySelector(".jiexiactive");
	url=class1.value;
	document.querySelector(".ddd").innerHTML =url+that.value;
	id.src=url+that.value;
	that.className="active";
}
</script>

